  ('pukao-d1056197-moex-00047', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '為防發生難以回復之損害，對於無效行政處分為暫時權利保護之聲請時，應聲請法院為下列何種措施？', '["假扣押", "假處分", "假執行", "停止執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00048', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '關於損失補償之敘述，下列何者錯誤？', '["須為違法行為", "騎樓禁止擺攤位不構成特別犧牲", "人民因機關即時強制致財產損失，得請求補償", "須基於公益之必要性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00049', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '依國家賠償法規定，下列何種情形並不成立國家賠償責任？', '["職司道路養護之公務員故意怠於履行職務，長期無視道路特定坑洞之存在，致使機車騎士行經該路段滑 倒受傷", "員警進行夜間定時巡邏業務，因過失未留意燈號變換而誤闖紅燈，撞上依燈號指示左轉之民眾車輛", "因過去已有多起溺水意外，主管機關於開放水域設置禁止游泳之警示標語，人民仍執意下水而喪失生命", "高速公路交流道設計與建造有所缺失，匝道彎度明顯過大，導致民眾車輛翻覆而駕駛受傷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00050', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '有關國家賠償之書面協議先行程序，下列敘述何者錯誤？', '["請求損害賠償時，於協議程序進行中，法院得依聲請為假處分，命賠償義務機關先行賠償損害", "請求損害賠償時，應先以書面向賠償義務機關請求之", "協議成立時，應作成協議書，該項協議書得為執行名義", "賠償義務機關拒絕賠償，請求權人得提起損害賠償之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00051', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '法律規定電子遊戲場業之營業場所應距離學校50公尺，但某直轄市自治條例卻規定為800公尺，依 司法院解釋意旨，下列敘述何者正確？', '["該自治條例無效，因違反法律優位原則", "該自治條例無效，因違反法律保留原則", "該自治條例有效，因後法優先於前法", "該自治條例有效，因地方有自治權限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00052', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '下列何者須以法律或法律明確授權之命令為依據始得為之？', '["開放公共空間供街頭藝人展演", "命法定傳染病之確診者居家隔離", "興建橋樑並提供公用", "提供空氣品質預報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00053', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '有關溯及既往與信賴保護原則之敘述，下列何者正確？', '["基於信賴保護原則，法規之適用均不得溯及既往", "真正溯及既往係指新制定之法規，適用於該法規生效前已完結之法律事實", "不真正溯及既往係指新制定之法規，僅適用於該法規生效後發生之法律事實", "不真正溯及既往之法規，不用考量人民對於舊法是否有值得保護之信賴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00054', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '教師及學校之教育或管理措施，即使構成權利之侵害，學生得據以提起行政爭訟請求救濟，但法院及 其他行政爭訟機關應予教師及學校較高之尊重。此屬下列何種概念？', '["行政保留", "裁量餘地", "專業判斷餘地", "法規制定裁量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00055', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '下列何者非屬私經濟行政行為？', '["中央銀行為穩定匯市，購買黃金外幣", "行政機關與得標廠商締結採購契約", "自來水公司提供配水服務", "直轄市政府依自治條例規定，同意相對人利用下水道附掛有線電視纜線並收取使用費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00056', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '關於公、私法法律關係之敘述，下列何者錯誤？', '["國宅之出租，屬私法關係", "政府發行公債，屬公法關係", "國立大學醫學系與其公費學生間，屬公法關係", "公立學校教師之聘任，屬公法關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL)
